def test_exact_match():
    assert search("apple", [Item("apple"), Item("banana")]) == [Item("apple")]

def test_fuzzy_match():
    # was passing in v2.2; v2.3 rewrite dropped fuzzy
    assert search("appel", [Item("apple")]) == [Item("apple")]
